static constexpr uint32_t ALIGN_ELEMS = 128;
static constexpr uint32_t HARD_CAP_ELEMS = 512;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvStandard3dSquareInputSquareKernelCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    uint32_t N = x_shape->GetDim(0);
    uint32_t C = x_shape->GetDim(1);
    uint32_t D = x_shape->GetDim(2);
    uint32_t H = x_shape->GetDim(3);
    uint32_t W = x_shape->GetDim(4);

    uint32_t Cout = w_shape->GetDim(0);
    uint32_t K = w_shape->GetDim(2);

    uint32_t Dout = D - K + 1;
    uint32_t Hout = H - K + 1;
    uint32_t Wout = W - K + 1;

