    tiling.set_Cout(Cout);
    tiling.set_K(K);
    tiling.set_Dout(Dout);
    tiling.set_Hout(Hout);
    tiling.set_Wout(Wout);
    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);

